window.BACTERIAL_TOPICS=[{"slug":"general","title":{"en":"General Principles","ar":"المبادئ العامة"},"count":6,"types":{"MCQ":4,"Case":2},"summary":{"en":"Pathogens, barrier disruption, MRSA risk, transmission, and supportive care.","ar":"الممرضات واختلال الحاجز الجلدي وخطر MRSA والانتقال والرعاية الداعمة."},"pearl":{"en":"Depth and host factors change both diagnosis and management.","ar":"عمق الإصابة وعوامل المريض يغيّران التشخيص وخطة العلاج."},"image":"assets/images/chapters/bacterial/bacterial-01.webp"},{"slug":"impetigo","title":{"en":"Impetigo","ar":"القوباء"},"count":20,"types":{"MCQ":8,"Case":6,"Treatment":3,"Image":3},"summary":{"en":"Non-bullous and bullous patterns, special variants, complications, and topical versus systemic therapy.","ar":"النوع غير الفقاعي والفقاعي والأنواع الخاصة والمضاعفات والاختيار بين العلاج الموضعي والجهازي."},"pearl":{"en":"Honey-colored crusts point toward non-bullous disease; fragile bullae suggest the toxin-mediated form.","ar":"القشور العسلية ترجح غير الفقاعي، والفقاعات الهشة ترجح النوع المرتبط بالسموم."},"image":"assets/images/chapters/bacterial/impetigo.webp"},{"slug":"ecthyma","title":{"en":"Ecthyma","ar":"الإكثيما"},"count":8,"types":{"MCQ":3,"Case":2,"Treatment":2,"Image":1},"summary":{"en":"A deeper ulcerative infection extending into the dermis, with wound care and systemic treatment principles.","ar":"عدوى تقرحية أعمق تمتد إلى الأدمة، مع مبادئ العناية بالجرح والعلاج الجهازي."},"pearl":{"en":"An adherent crust over a punched-out ulcer is the key clue.","ar":"القشرة الملتصقة فوق قرحة محفورة هي العلامة الأهم."},"image":"assets/images/chapters/bacterial/ecthyma.webp"},{"slug":"erythrasma","title":{"en":"Erythrasma","ar":"الإريثرازما"},"count":8,"types":{"MCQ":3,"Case":2,"Treatment":2,"Image":1},"summary":{"en":"Flexural reddish-brown patches, Wood lamp diagnosis, risk factors, and treatment options.","ar":"لطخات بنية محمرة في الثنيات وتشخيص مصباح وود وعوامل الخطورة وخيارات العلاج."},"pearl":{"en":"Coral-red fluorescence is a high-yield discriminator.","ar":"التألق الأحمر المرجاني علامة فارقة عالية الأهمية."},"image":"assets/images/chapters/bacterial/erythrasma.webp"},{"slug":"erysipelas","title":{"en":"Erysipelas","ar":"الحمرة"},"count":10,"types":{"MCQ":4,"Case":4,"Image":1,"Treatment":1},"summary":{"en":"Superficial lymphatic infection with abrupt onset, raised borders, systemic features, and referral clues.","ar":"عدوى سطحية بالجهاز اللمفي ذات بداية مفاجئة وحدود مرتفعة وأعراض جهازية وعلامات إحالة."},"pearl":{"en":"A shiny, raised, sharply demarcated plaque favors erysipelas over cellulitis.","ar":"اللويحة اللامعة المرتفعة محددة الحدود ترجح الحمرة على التهاب النسيج الخلوي."},"image":"assets/images/chapters/bacterial/erysipelas.webp"},{"slug":"cellulitis","title":{"en":"Cellulitis","ar":"التهاب النسيج الخلوي"},"count":26,"types":{"MCQ":7,"Case":9,"Treatment":8,"Image":2},"summary":{"en":"Nonpurulent versus purulent disease, risk stratification, empiric therapy, red flags, and escalation.","ar":"الحالات غير القيحية والقيحية وتقييم الخطورة والعلاج التجريبي وعلامات الخطر والتصعيد."},"pearl":{"en":"Pain out of proportion, rapid progression, or toxicity should trigger urgent reassessment.","ar":"الألم غير المتناسب أو الانتشار السريع أو السمية الجهازية تستدعي تقييمًا عاجلًا."},"image":"assets/images/chapters/bacterial/cellulitis.webp"},{"slug":"folliculitis","title":{"en":"Bacterial Folliculitis","ar":"التهاب جريبات الشعر البكتيري"},"count":14,"types":{"MCQ":5,"Case":3,"Treatment":5,"Image":1},"summary":{"en":"Follicle-centered pustules, common causes, hot-tub disease, differential diagnosis, and therapy.","ar":"بثور متمركزة حول الجريبات والمسببات الشائعة والتهاب الحمام الساخن والتشخيص التفريقي والعلاج."},"pearl":{"en":"The follicular center is the visual anchor for diagnosis.","ar":"تمركز الآفة حول جريب الشعر هو المفتاح البصري للتشخيص."},"image":"assets/images/chapters/bacterial/folliculitis.webp"},{"slug":"furuncle","title":{"en":"Furuncle","ar":"الدُّمَّل"},"count":8,"types":{"MCQ":3,"Case":2,"Treatment":2,"Image":1},"summary":{"en":"Deep follicular infection, fluctuation, drainage, antibiotic indications, and recurrence prevention.","ar":"عدوى جريبية عميقة والتذبذب والتصريف ودواعي المضاد الحيوي والوقاية من التكرار."},"pearl":{"en":"Source control matters when a drainable abscess is present.","ar":"السيطرة على مصدر العدوى مهمة عند وجود خراج قابل للتصريف."},"image":"assets/images/chapters/bacterial/furuncle.webp"},{"slug":"carbuncle","title":{"en":"Carbuncle","ar":"الجَمْرَة"},"count":8,"types":{"MCQ":4,"Case":2,"Treatment":1,"Image":1},"summary":{"en":"Coalescent furuncles with multiple drainage points, systemic risk, source control, and escalation.","ar":"دمامل متصلة ذات فتحات تصريف متعددة وخطر جهازي والسيطرة على المصدر والتصعيد."},"pearl":{"en":"Multiple draining points and a larger indurated mass distinguish a carbuncle.","ar":"تعدد فتحات التصريف مع كتلة كبيرة متصلبة يميز الجمرة."},"image":"assets/images/chapters/bacterial/carbuncle.webp"},{"slug":"cat-scratch","title":{"en":"Cat Scratch Disease","ar":"مرض خدش القطة"},"count":16,"types":{"MCQ":5,"Case":6,"Treatment":3,"Image":2},"summary":{"en":"Inoculation papule, regional lymphadenopathy, atypical disease, testing, and antimicrobial decisions.","ar":"حطاطة التلقيح وتضخم العقد اللمفية الموضعي والحالات غير النمطية والفحوص والقرارات العلاجية."},"pearl":{"en":"The exposure history plus delayed regional nodes is the core pattern.","ar":"تاريخ التعرض مع ظهور تضخم عقدي موضعي لاحقًا هو النمط الأساسي."},"image":"assets/images/chapters/bacterial/cat-scratch.webp"},{"slug":"anthrax","title":{"en":"Cutaneous Anthrax","ar":"الجمرة الخبيثة الجلدية"},"count":12,"types":{"MCQ":5,"Case":2,"Image":1,"Treatment":4},"summary":{"en":"Painless papule-to-eschar evolution, marked edema, exposure history, urgent diagnosis, and therapy.","ar":"تطور الآفة غير المؤلمة إلى قشرة سوداء مع وذمة واضحة وتاريخ التعرض والتشخيص والعلاج العاجل."},"pearl":{"en":"A painless black eschar with disproportionate edema is a major warning pattern.","ar":"القشرة السوداء غير المؤلمة مع وذمة كبيرة نمط إنذاري مهم."},"image":"data:image/webp;base64,"},{"slug":"ssss","title":{"en":"Staphylococcal Scalded Skin Syndrome","ar":"متلازمة الجلد المسموط العنقودية"},"count":14,"types":{"MCQ":4,"Case":5,"Image":1,"Treatment":4},"summary":{"en":"Exfoliative toxin disease, widespread tenderness and peeling, supportive care, antibiotics, and complications.","ar":"مرض بوساطة السموم التقشرية مع ألم وتقشر واسع ورعاية داعمة ومضادات ومضاعفات."},"pearl":{"en":"Superficial toxin-mediated separation is not managed like a deep necrotizing infection.","ar":"الانفصال السطحي الناتج عن السموم لا يُعامل كعدوى نخرية عميقة."},"image":"assets/images/chapters/bacterial/ssss.webp"}];
