window.BACTERIAL_QUESTIONS=window.BACTERIAL_QUESTIONS.concat([{"id":"Q001","topic":"general","topicEn":"General Principles","topicAr":"المبادئ العامة","type":"MCQ","difficulty":"Easy","source":"PDF pp. 2-3","question":{"en":"Which two organisms are the leading causes of bacterial skin infections in this chapter?","ar":"ما الكائنان الدقيقان اللذان يمثلان السببين الرئيسيين لعدوى الجلد البكتيرية في هذا الفصل؟"},"options":[{"letter":"A","en":"Staphylococcus aureus and Streptococcus pyogenes","ar":"المكورات العنقودية الذهبية والعقدية المقيحة"},{"letter":"B","en":"Pseudomonas aeruginosa and Candida albicans","ar":"الزائفة الزنجارية والمبيضة البيضاء"},{"letter":"C","en":"Escherichia coli and Klebsiella pneumoniae","ar":"الإشريكية القولونية والكليبسيلا الرئوية"},{"letter":"D","en":"Mycobacterium tuberculosis and Treponema pallidum","ar":"المتفطرة السلية واللولبية الشاحبة"}],"correct":"A","explanation":{"en":"Staphylococcus aureus and Streptococcus pyogenes are the dominant gram-positive pathogens in common superficial and deep bacterial skin infections.","ar":"تُعد المكورات العنقودية الذهبية والعقدية المقيحة أهم الممرضات إيجابية الغرام في العدوى الجلدية البكتيرية السطحية والعميقة الشائعة."},"reasoning":{"en":"Focus on the chapter repeatedly links these two organisms to impetigo, folliculitis, erysipelas, and cellulitis. This clue supports option A and makes the alternatives less consistent with the chapter’s clinical pattern.","ar":"ركّز على يربط الفصل بصورة متكررة هذين الميكروبين بالقوباء والتهاب الجريبات والحمرة والتهاب النسيج الخلوي. تدعم هذه العلامة الخيار A وتجعل البدائل أقل توافقًا مع النمط السريري المذكور في الفصل."},"image":null},{"id":"Q002","topic":"general","topicEn":"General Principles","topicAr":"المبادئ العامة","type":"MCQ","difficulty":"Easy","source":"PDF p. 2","question":{"en":"What most directly determines whether a bacterial skin infection is classified as superficial or deep?","ar":"ما العامل الذي يحدد بصورة مباشرة تصنيف عدوى الجلد البكتيرية إلى سطحية أو عميقة؟"},"options":[{"letter":"A","en":"The depth of tissue invasion","ar":"عمق اختراق الأنسجة"},{"letter":"B","en":"The patient’s age alone","ar":"عمر المريض فقط"},{"letter":"C","en":"The color of the lesion","ar":"لون الآفة"},{"letter":"D","en":"The season of presentation","ar":"فصل السنة عند ظهور الحالة"}],"correct":"A","explanation":{"en":"The anatomical depth reached by the infection distinguishes epidermal or follicular disease from dermal and subcutaneous disease.","ar":"يُميز العمق التشريحي الذي تصل إليه العدوى بين المرض المحدود بالبشرة أو الجريب وبين إصابة الأدمة والأنسجة تحت الجلد."},"reasoning":{"en":"Focus on superficial disease stays in the epidermis or follicle, whereas deeper disease involves dermis or subcutis. This clue supports option A and makes the alternatives less consistent with the chapter’s clinical pattern.","ar":"ركّز على تبقى العدوى السطحية في البشرة أو الجريب بينما تشمل العدوى العميقة الأدمة أو النسيج تحت الجلد. تدعم هذه العلامة الخيار A وتجعل البدائل أقل توافقًا مع النمط السريري المذكور في الفصل."},"image":null},{"id":"Q003","topic":"general","topicEn":"General Principles","topicAr":"المبادئ العامة","type":"Case","difficulty":"Medium","source":"PDF pp. 2, 15","question":{"en":"A patient with diabetes, chronic leg edema, and a new skin fissure develops spreading erythema. Which host factors most plausibly facilitated invasion?","ar":"مريض يعاني السكري ووذمة مزمنة بالساق مع شق جلدي حديث، ثم ظهر لديه احمرار ممتد. ما عوامل المضيف الأكثر احتمالًا لتسهيل الغزو البكتيري؟"},"options":[{"letter":"A","en":"Barrier disruption plus impaired host defense","ar":"اختلال الحاجز الجلدي مع ضعف دفاعات المضيف"},{"letter":"B","en":"Normal flora eradication by sunlight","ar":"القضاء على الفلورا الطبيعية بواسطة ضوء الشمس"},{"letter":"C","en":"High calcium intake","ar":"تناول كميات مرتفعة من الكالسيوم"},{"letter":"D","en":"Low ambient humidity alone","ar":"انخفاض رطوبة الجو فقط"}],"correct":"A","explanation":{"en":"Skin disruption creates an entry point, while diabetes and chronic edema impair local defense and healing.","ar":"يُنشئ اختلال الجلد منفذًا للدخول، بينما يضعف السكري والوذمة المزمنة الدفاع الموضعي والالتئام."},"reasoning":{"en":"Focus on the combination of an entry portal and comorbidities is more important than any isolated environmental factor. This clue supports option A and makes the alternatives less consistent with the chapter’s clinical pattern.","ar":"ركّز على اجتماع منفذ دخول مع أمراض مصاحبة أهم من أي عامل بيئي منفرد. تدعم هذه العلامة الخيار A وتجعل البدائل أقل توافقًا مع النمط السريري المذكور في الفصل."},"image":null},{"id":"Q004","topic":"general","topicEn":"General Principles","topicAr":"المبادئ العامة","type":"MCQ","difficulty":"Easy","source":"PDF pp. 2, 18","question":{"en":"When should empiric MRSA coverage receive particular consideration in bacterial skin infection?","ar":"متى ينبغي الاهتمام بصورة خاصة بالتغطية التجريبية للمكورات العنقودية الذهبية المقاومة للميثيسيلين؟"},"options":[{"letter":"A","en":"Purulent or recurrent infection","ar":"العدوى القيحية أو المتكررة"},{"letter":"B","en":"Every mild localized nonpurulent rash","ar":"كل طفح خفيف موضعي غير قيحي"},{"letter":"C","en":"Only after complete clinical recovery","ar":"فقط بعد التعافي السريري الكامل"},{"letter":"D","en":"Only in fungal coinfection","ar":"فقط عند وجود عدوى فطرية مصاحبة"}],"correct":"A","explanation":{"en":"Purulence, recurrence, prior MRSA, colonization, injection drug use, and systemic toxicity increase the need for MRSA-active therapy.","ar":"تزيد القيحية والتكرار والسوابق أو الاستعمار بالـMRSA وتعاطي المخدرات بالحقن والسمية الجهازية من الحاجة إلى علاج فعال ضدها."},"reasoning":{"en":"Focus on purulence and recurrence shift the likely pathogen and resistance profile. This clue supports option A and makes the alternatives less consistent with the chapter’s clinical pattern.","ar":"ركّز على تُغيّر القيحية والتكرار احتمالية الممرض ونمط المقاومة. تدعم هذه العلامة الخيار A وتجعل البدائل أقل توافقًا مع النمط السريري المذكور في الفصل."},"image":null},{"id":"Q005","topic":"general","topicEn":"General Principles","topicAr":"المبادئ العامة","type":"Case","difficulty":"Medium","source":"PDF pp. 3-4","question":{"en":"A localized infection improves with appropriate antibiotics, but the patient continues scratching and sharing towels. What is the main preventable risk?","ar":"تحسنت عدوى موضعية بالمضاد المناسب، لكن المريض ما زال يحك الجلد ويشارك المناشف. ما الخطر القابل للوقاية الأهم؟"},"options":[{"letter":"A","en":"Transmission and recurrence","ar":"انتقال العدوى وتكرارها"},{"letter":"B","en":"Immediate renal failure","ar":"فشل كلوي فوري"},{"letter":"C","en":"Drug-induced hyperthyroidism","ar":"فرط الدرقية الدوائي"},{"letter":"D","en":"Permanent bacterial immunity","ar":"مناعة بكتيرية دائمة"}],"correct":"A","explanation":{"en":"Hygiene, avoidance of scratching, and not sharing contaminated items help limit autoinoculation, transmission, and recurrence.","ar":"تساعد النظافة وتجنب الحك وعدم مشاركة الأدوات الملوثة على تقليل التلقيح الذاتي وانتقال العدوى وتكرارها."},"reasoning":{"en":"Focus on antibiotics alone do not correct behaviors that continue spreading organisms. This clue supports option A and makes the alternatives less consistent with the chapter’s clinical pattern.","ar":"ركّز على لا تُصلح المضادات الحيوية وحدها السلوكيات التي تستمر في نشر الميكروبات. تدعم هذه العلامة الخيار A وتجعل البدائل أقل توافقًا مع النمط السريري المذكور في الفصل."},"image":null},{"id":"Q006","topic":"general","topicEn":"General Principles","topicAr":"المبادئ العامة","type":"MCQ","difficulty":"Easy","source":"PDF pp. 2-3","question":{"en":"Which supportive measure is consistently emphasized as part of recovery from bacterial skin infection?","ar":"أي إجراء داعم يُؤكد عليه باستمرار كجزء من التعافي من عدوى الجلد البكتيرية؟"},"options":[{"letter":"A","en":"Hygiene, hydration, nutrition, and control of comorbidities","ar":"النظافة والترطيب والتغذية وضبط الأمراض المصاحبة"},{"letter":"B","en":"Routine systemic corticosteroids for all patients","ar":"الكورتيكوستيرويدات الجهازية روتينيًا لكل المرضى"},{"letter":"C","en":"Occlusive dressings for every lesion","ar":"الضمادات المحكمة لكل آفة"},{"letter":"D","en":"Stopping antibiotics once pain decreases","ar":"إيقاف المضاد بمجرد انخفاض الألم"}],"correct":"A","explanation":{"en":"Supportive care improves healing and reduces recurrence but complements rather than replaces appropriate antimicrobial or surgical treatment.","ar":"تُحسن الرعاية الداعمة الالتئام وتقلل التكرار، لكنها تُكمل العلاج المضاد للميكروبات أو الجراحي المناسب ولا تستبدله."},"reasoning":{"en":"Focus on the chapter explicitly combines pharmacologic therapy with hygiene, hydration, nutrition, and comorbidity control. This clue supports option A and makes the alternatives less consistent with the chapter’s clinical pattern.","ar":"ركّز على يجمع الفصل صراحة بين العلاج الدوائي والنظافة والترطيب والتغذية وضبط الأمراض المصاحبة. تدعم هذه العلامة الخيار A وتجعل البدائل أقل توافقًا مع النمط السريري المذكور في الفصل."},"image":null},{"id":"Q007","topic":"impetigo","topicEn":"Impetigo","topicAr":"القوباء","type":"MCQ","difficulty":"Easy","source":"PDF p. 4","question":{"en":"Impetigo primarily involves which anatomical layer?","ar":"تُصيب القوباء بصورة أساسية أي طبقة تشريحية؟"},"options":[{"letter":"A","en":"Superficial epidermis","ar":"البشرة السطحية"},{"letter":"B","en":"Deep fascia","ar":"اللفافة العميقة"},{"letter":"C","en":"Skeletal muscle","ar":"العضلات الهيكلية"},{"letter":"D","en":"Periosteum","ar":"السمحاق"}],"correct":"A","explanation":{"en":"Impetigo is a superficial and highly contagious infection confined mainly to the epidermis.","ar":"القوباء عدوى سطحية شديدة العدوى تقتصر أساسًا على البشرة."},"reasoning":{"en":"Focus on the superficial location explains crusted erosions without deep tissue destruction. This clue supports option A and makes the alternatives less consistent with the chapter’s clinical pattern.","ar":"ركّز على يفسر الموقع السطحي وجود تآكلات متقشرة دون تدمير عميق للأنسجة. تدعم هذه العلامة الخيار A وتجعل البدائل أقل توافقًا مع النمط السريري المذكور في الفصل."},"image":null},{"id":"Q008","topic":"impetigo","topicEn":"Impetigo","topicAr":"القوباء","type":"MCQ","difficulty":"Easy","source":"PDF p. 4","question":{"en":"In which age group is impetigo most typical?","ar":"في أي فئة عمرية تكون القوباء أكثر شيوعًا؟"},"options":[{"letter":"A","en":"Children aged about 2-5 years","ar":"الأطفال بعمر يقارب 2-5 سنوات"},{"letter":"B","en":"Adults older than 80 years only","ar":"البالغون فوق 80 عامًا فقط"},{"letter":"C","en":"Neonates exclusively","ar":"حديثو الولادة حصريًا"},{"letter":"D","en":"Only adolescents","ar":"المراهقون فقط"}],"correct":"A","explanation":{"en":"Impetigo is especially common in young children, although adults may be affected when risk factors are present.","ar":"تشيع القوباء خصوصًا في الأطفال الصغار، مع إمكانية إصابة البالغين عند وجود عوامل خطورة."},"reasoning":{"en":"Focus on the typical epidemiologic clue is a preschool child with contagious superficial lesions. This clue supports option A and makes the alternatives less consistent with the chapter’s clinical pattern.","ar":"ركّز على الدليل الوبائي المعتاد هو طفل قبل سن المدرسة لديه آفات سطحية معدية. تدعم هذه العلامة الخيار A وتجعل البدائل أقل توافقًا مع النمط السريري المذكور في الفصل."},"image":null},{"id":"Q009","topic":"impetigo","topicEn":"Impetigo","topicAr":"القوباء","type":"MCQ","difficulty":"Easy","source":"PDF pp. 4-5","question":{"en":"Which lesion description is classic for non-bullous impetigo?","ar":"أي وصف للآفة يُعد نموذجيًا للقوباء غير الفقاعية؟"},"options":[{"letter":"A","en":"Fragile vesicles that leave honey-colored crusts","ar":"حويصلات هشة تترك قشورًا بلون العسل"},{"letter":"B","en":"Painless black eschar with massive edema","ar":"قشرة سوداء غير مؤلمة مع وذمة شديدة"},{"letter":"C","en":"Sharply raised red plaque with fever","ar":"لويحة حمراء مرتفعة محددة مع حمى"},{"letter":"D","en":"Deep fluctuant nodule with a necrotic core","ar":"عقدة عميقة متموجة ذات مركز نخري"}],"correct":"A","explanation":{"en":"Non-bullous impetigo produces fragile vesicles or pustules that rupture and form characteristic honey-colored crusts.","ar":"تُحدث القوباء غير الفقاعية حويصلات أو بثورًا هشة تتمزق وتكوّن القشور المميزة بلون العسل."},"reasoning":{"en":"Focus on honey-colored crusting is the most discriminating morphology among the options. This clue supports option A and makes the alternatives less consistent with the chapter’s clinical pattern.","ar":"ركّز على القشور بلون العسل هي العلامة الشكلية الأكثر تمييزًا بين الخيارات. تدعم هذه العلامة الخيار A وتجعل البدائل أقل توافقًا مع النمط السريري المذكور في الفصل."},"image":null},{"id":"Q010","topic":"impetigo","topicEn":"Impetigo","topicAr":"القوباء","type":"Case","difficulty":"Medium","source":"PDF p. 5","question":{"en":"A 4-year-old has perioral honey-colored crusts and regional lymphadenopathy but no fever. Which form is most likely?","ar":"طفل عمره 4 سنوات لديه قشور بلون العسل حول الفم مع تضخم عقد لمفية موضعية دون حمى. ما الشكل الأكثر احتمالًا؟"},"options":[{"letter":"A","en":"Non-bullous impetigo","ar":"القوباء غير الفقاعية"},{"letter":"B","en":"Bullous impetigo","ar":"القوباء الفقاعية"},{"letter":"C","en":"Ecthyma","ar":"الإكثيما"},{"letter":"D","en":"Cellulitis","ar":"التهاب النسيج الخلوي"}],"correct":"A","explanation":{"en":"Non-bullous impetigo commonly affects the face, produces honey-colored crusts, and may have regional lymphadenopathy with few constitutional symptoms.","ar":"تُصيب القوباء غير الفقاعية الوجه غالبًا وتُنتج قشورًا بلون العسل وقد يصاحبها تضخم عقدي موضعي مع أعراض جهازية قليلة."},"reasoning":{"en":"Focus on face distribution, honey crusts, and lymphadenopathy favor the non-bullous form. This clue supports option A and makes the alternatives less consistent with the chapter’s clinical pattern.","ar":"ركّز على يرجح توزع الوجه والقشور العسلية والتضخم العقدي الشكل غير الفقاعي. تدعم هذه العلامة الخيار A وتجعل البدائل أقل توافقًا مع النمط السريري المذكور في الفصل."},"image":null},{"id":"Q011","topic":"impetigo","topicEn":"Impetigo","topicAr":"القوباء","type":"MCQ","difficulty":"Medium","source":"PDF pp. 4-5","question":{"en":"Bullous impetigo is specifically linked to which mechanism?","ar":"بأي آلية ترتبط القوباء الفقاعية تحديدًا؟"},"options":[{"letter":"A","en":"Exfoliative toxins from Staphylococcus aureus","ar":"سموم تقشرية من المكورات العنقودية الذهبية"},{"letter":"B","en":"Endotoxin from Escherichia coli","ar":"ذيفان داخلي من الإشريكية القولونية"},{"letter":"C","en":"Immune complexes after fungal infection","ar":"معقدات مناعية بعد عدوى فطرية"},{"letter":"D","en":"Direct invasion of skeletal muscle","ar":"غزو مباشر للعضلات الهيكلية"}],"correct":"A","explanation":{"en":"Toxigenic S. aureus produces exfoliative toxins that cause superficial blister formation in bullous impetigo.","ar":"تُنتج سلالات المكورات العنقودية الذهبية السامة سمومًا تقشرية تسبب تكون الفقاعات السطحية."},"reasoning":{"en":"Focus on the bullous form is toxin-mediated rather than primarily streptococcal. This clue supports option A and makes the alternatives less consistent with the chapter’s clinical pattern.","ar":"ركّز على الشكل الفقاعي بوساطة السموم وليس عقديًا في الأساس. تدعم هذه العلامة الخيار A وتجعل البدائل أقل توافقًا مع النمط السريري المذكور في الفصل."},"image":null},{"id":"Q012","topic":"impetigo","topicEn":"Impetigo","topicAr":"القوباء","type":"Case","difficulty":"Medium","source":"PDF p. 5","question":{"en":"A child develops rapidly forming thin-roofed bullae on the trunk that rupture and leave a collarette of scale. What is the diagnosis?","ar":"ظهر لدى طفل فقاعات رقيقة السقف تتكون سريعًا على الجذع ثم تتمزق وتترك طوقًا قشريًا. ما التشخيص؟"},"options":[{"letter":"A","en":"Bullous impetigo","ar":"القوباء الفقاعية"},{"letter":"B","en":"Non-bullous impetigo","ar":"القوباء غير الفقاعية"},{"letter":"C","en":"Erythrasma","ar":"الإريثرازما"},{"letter":"D","en":"Furuncle","ar":"الدمل"}],"correct":"A","explanation":{"en":"Thin superficial bullae with yellow fluid and a residual collarette are characteristic of bullous impetigo.","ar":"تُعد الفقاعات السطحية الرقيقة ذات السائل الأصفر والطوق القشري المتبقي مميزة للقوباء الفقاعية."},"reasoning":{"en":"Focus on the collarette after rupture is a classic bullous clue. This clue supports option A and makes the alternatives less consistent with the chapter’s clinical pattern.","ar":"ركّز على الطوق القشري بعد التمزق علامة كلاسيكية للشكل الفقاعي. تدعم هذه العلامة الخيار A وتجعل البدائل أقل توافقًا مع النمط السريري المذكور في الفصل."},"image":null},{"id":"Q013","topic":"impetigo","topicEn":"Impetigo","topicAr":"القوباء","type":"MCQ","difficulty":"Medium","source":"PDF p. 5","question":{"en":"Which finding is more typical of bullous than non-bullous impetigo?","ar":"أي علامة تكون أكثر شيوعًا في القوباء الفقاعية مقارنة بغير الفقاعية؟"},"options":[{"letter":"A","en":"Constitutional symptoms such as fever or malaise","ar":"أعراض عامة مثل الحمى أو الإعياء"},{"letter":"B","en":"Frequent regional lymphadenopathy","ar":"تضخم عقد لمفية موضعي متكرر"},{"letter":"C","en":"Honey-colored crusts around the nose","ar":"قشور عسلية حول الأنف"},{"letter":"D","en":"Association with pediculosis of the scalp","ar":"ارتباط بقمل فروة الرأس"}],"correct":"A","explanation":{"en":"Bullous impetigo is more often accompanied by constitutional symptoms, whereas regional lymphadenopathy is more typical of non-bullous disease.","ar":"يرتبط الشكل الفقاعي أكثر بالأعراض العامة، بينما يكون التضخم العقدي الموضعي أكثر شيوعًا في الشكل غير الفقاعي."},"reasoning":{"en":"Focus on comparing systemic symptoms and lymph nodes separates the two forms. This clue supports option A and makes the alternatives less consistent with the chapter’s clinical pattern.","ar":"ركّز على تساعد مقارنة الأعراض العامة والعقد اللمفية في التفريق بين الشكلين. تدعم هذه العلامة الخيار A وتجعل البدائل أقل توافقًا مع النمط السريري المذكور في الفصل."},"image":null},{"id":"Q014","topic":"impetigo","topicEn":"Impetigo","topicAr":"القوباء","type":"MCQ","difficulty":"Medium","source":"PDF p. 5","question":{"en":"Which finding is more typical of non-bullous impetigo?","ar":"أي علامة تكون أكثر شيوعًا في القوباء غير الفقاعية؟"},"options":[{"letter":"A","en":"Regional lymphadenopathy","ar":"تضخم العقد اللمفية الموضعية"},{"letter":"B","en":"Large thin-roofed bullae on intact trunk skin","ar":"فقاعات كبيرة رقيقة السقف على جلد الجذع السليم"},{"letter":"C","en":"Marked constitutional toxicity","ar":"سمية جهازية واضحة"},{"letter":"D","en":"Multiple draining sinuses","ar":"جيوب متعددة مفرغة للقيح"}],"correct":"A","explanation":{"en":"Regional lymphadenopathy is common in non-bullous impetigo and uncommon in bullous disease.","ar":"يشيع تضخم العقد اللمفية الموضعية في القوباء غير الفقاعية ويقل في الشكل الفقاعي."},"reasoning":{"en":"Focus on lymph-node involvement is a useful comparative feature. This clue supports option A and makes the alternatives less consistent with the chapter’s clinical pattern.","ar":"ركّز على إصابة العقد اللمفية علامة مقارنة مفيدة. تدعم هذه العلامة الخيار A وتجعل البدائل أقل توافقًا مع النمط السريري المذكور في الفصل."},"image":null},{"id":"Q015","topic":"impetigo","topicEn":"Impetigo","topicAr":"القوباء","type":"Case","difficulty":"Easy","source":"PDF p. 4","question":{"en":"Several siblings develop similar crusted lesions after sharing towels. What is the most likely route of spread?","ar":"أصيب عدة أشقاء بآفات متقشرة متشابهة بعد مشاركة المناشف. ما طريق الانتقال الأكثر احتمالًا؟"},"options":[{"letter":"A","en":"Direct contact or contaminated fomites","ar":"التلامس المباشر أو الأدوات الملوثة"},{"letter":"B","en":"Airborne spread over long distances","ar":"الانتقال الهوائي لمسافات طويلة"},{"letter":"C","en":"Mosquito-borne transmission","ar":"الانتقال بواسطة البعوض"},{"letter":"D","en":"Vertical transmission during birth only","ar":"الانتقال الرأسي أثناء الولادة فقط"}],"correct":"A","explanation":{"en":"Impetigo spreads readily through contact with lesions or contaminated objects such as towels.","ar":"تنتشر القوباء بسهولة عبر ملامسة الآفات أو الأدوات الملوثة مثل المناشف."},"reasoning":{"en":"Focus on the clustered household pattern after towel sharing points to fomites. This clue supports option A and makes the alternatives less consistent with the chapter’s clinical pattern.","ar":"ركّز على يشير التجمع الأسري بعد مشاركة المناشف إلى الأدوات الملوثة. تدعم هذه العلامة الخيار A وتجعل البدائل أقل توافقًا مع النمط السريري المذكور في الفصل."},"image":null},{"id":"Q016","topic":"impetigo","topicEn":"Impetigo","topicAr":"القوباء","type":"MCQ","difficulty":"Medium","source":"PDF pp. 4, 6","question":{"en":"Which important immune-mediated complication may follow streptococcal impetigo?","ar":"أي مضاعفة مناعية مهمة قد تتبع القوباء العقدية؟"},"options":[{"letter":"A","en":"Post-streptococcal acute glomerulonephritis","ar":"التهاب كبيبات الكلى الحاد التالي للعقديات"},{"letter":"B","en":"Myasthenia gravis","ar":"الوهن العضلي الوبيل"},{"letter":"C","en":"Acute pancreatitis","ar":"التهاب البنكرياس الحاد"},{"letter":"D","en":"Pernicious anemia","ar":"فقر الدم الخبيث"}],"correct":"A","explanation":{"en":"Post-streptococcal acute glomerulonephritis is a recognized complication of impetigo caused by nephritogenic streptococcal strains.","ar":"يُعد التهاب كبيبات الكلى الحاد التالي للعقديات مضاعفة معروفة للقوباء الناتجة عن سلالات عقدية مولدة لالتهاب الكلى."},"reasoning":{"en":"Focus on the complication follows streptococcal skin infection and is not a direct local extension. This clue supports option A and makes the alternatives less consistent with the chapter’s clinical pattern.","ar":"ركّز على تحدث المضاعفة بعد عدوى جلدية عقدية وليست امتدادًا موضعيًا مباشرًا. تدعم هذه العلامة الخيار A وتجعل البدائل أقل توافقًا مع النمط السريري المذكور في الفصل."},"image":null},{"id":"Q017","topic":"impetigo","topicEn":"Impetigo","topicAr":"القوباء","type":"MCQ","difficulty":"Easy","source":"PDF pp. 8, 10","question":{"en":"What is the preferred initial treatment for a few localized impetigo lesions?","ar":"ما العلاج الأولي المفضل لعدد قليل من آفات القوباء الموضعية؟"},"options":[{"letter":"A","en":"Topical mupirocin","ar":"ميوبيروسين موضعي"},{"letter":"B","en":"IV meropenem","ar":"ميروبينيم وريدي"},{"letter":"C","en":"Oral fluconazole","ar":"فلوكونازول فموي"},{"letter":"D","en":"Surgical debridement","ar":"تنضير جراحي"}],"correct":"A","explanation":{"en":"Topical mupirocin is first-line for limited impetigo because it is effective and minimizes systemic exposure.","ar":"يُعد الميوبيروسين الموضعي خط العلاج الأول للقوباء المحدودة لفعاليته وتقليل التعرض الجهازي."},"reasoning":{"en":"Focus on localized superficial disease can be treated topically without broad systemic therapy. This clue supports option A and makes the alternatives less consistent with the chapter’s clinical pattern.","ar":"ركّز على يمكن علاج العدوى السطحية الموضعية موضعيًا دون علاج جهازي واسع. تدعم هذه العلامة الخيار A وتجعل البدائل أقل توافقًا مع النمط السريري المذكور في الفصل."},"image":null},{"id":"Q018","topic":"impetigo","topicEn":"Impetigo","topicAr":"القوباء","type":"Treatment","difficulty":"Medium","source":"PDF pp. 9-10","question":{"en":"Which regimen best matches the chapter recommendation for extensive impetigo without MRSA risk?","ar":"أي نظام يتوافق أفضل مع توصية الفصل للقوباء الواسعة دون خطر MRSA؟"},"options":[{"letter":"A","en":"Oral cephalexin for about 7 days","ar":"سيفاليكسين فموي لنحو 7 أيام"},{"letter":"B","en":"Topical steroid alone","ar":"ستيرويد موضعي فقط"},{"letter":"C","en":"Single dose of vancomycin","ar":"جرعة واحدة من فانكوميسين"},{"letter":"D","en":"Oral acyclovir","ar":"أسيكلوفير فموي"}],"correct":"A","explanation":{"en":"Extensive impetigo requires systemic anti-staphylococcal and anti-streptococcal therapy; cephalexin is a common first-line option.","ar":"تحتاج القوباء الواسعة إلى علاج جهازي فعال ضد العنقوديات والعقديات، ويُعد السيفاليكسين خيارًا أوليًا شائعًا."},"reasoning":{"en":"Focus on extent changes management from topical to oral therapy. This clue supports option A and makes the alternatives less consistent with the chapter’s clinical pattern.","ar":"ركّز على يُحوّل اتساع المرض العلاج من الموضعي إلى الفموي. تدعم هذه العلامة الخيار A وتجعل البدائل أقل توافقًا مع النمط السريري المذكور في الفصل."},"image":null},{"id":"Q019","topic":"impetigo","topicEn":"Impetigo","topicAr":"القوباء","type":"Case","difficulty":"Medium","source":"PDF pp. 9-10","question":{"en":"A patient has extensive impetigo with confirmed MRSA. Which oral option is appropriate according to the chapter?","ar":"مريض لديه قوباء واسعة مع تأكيد MRSA. أي خيار فموي مناسب وفقًا للفصل؟"},"options":[{"letter":"A","en":"Doxycycline","ar":"دوكسيسيكلين"},{"letter":"B","en":"Penicillin V alone","ar":"بنسلين V وحده"},{"letter":"C","en":"Amoxicillin alone","ar":"أموكسيسيلين وحده"},{"letter":"D","en":"Erythromycin regardless of susceptibility","ar":"إريثرومايسين بصرف النظر عن الحساسية"}],"correct":"A","explanation":{"en":"Doxycycline, TMP-SMX, or clindamycin may be used when MRSA is suspected or confirmed, depending on susceptibility and patient factors.","ar":"يمكن استخدام الدوكسيسيكلين أو TMP-SMX أو الكليندامايسين عند الاشتباه أو التأكد من MRSA حسب الحساسية وعوامل المريض."},"reasoning":{"en":"Focus on confirmed MRSA requires an agent with reliable MRSA activity. This clue supports option A and makes the alternatives less consistent with the chapter’s clinical pattern.","ar":"ركّز على يتطلب تأكيد MRSA دواءً ذا فعالية موثوقة ضدها. تدعم هذه العلامة الخيار A وتجعل البدائل أقل توافقًا مع النمط السريري المذكور في الفصل."},"image":null},{"id":"Q020","topic":"impetigo","topicEn":"Impetigo","topicAr":"القوباء","type":"Treatment","difficulty":"Medium","source":"PDF p. 9","question":{"en":"When is penicillin V most rational in impetigo or ecthyma?","ar":"متى يكون البنسلين V اختيارًا منطقيًا أكثر في القوباء أو الإكثيما؟"},"options":[{"letter":"A","en":"When infection is proven to be purely beta-hemolytic streptococcal","ar":"عندما تُثبت العدوى بأنها عقدية حالّة للدم بيتا فقط"},{"letter":"B","en":"Whenever MRSA is suspected","ar":"كلما اشتُبه في MRSA"},{"letter":"C","en":"For hot-tub folliculitis","ar":"لالتهاب الجريبات المرتبط بحمام ساخن"},{"letter":"D","en":"For toxin-mediated bullous disease regardless of culture","ar":"للمرض الفقاعي السمي بصرف النظر عن المزرعة"}],"correct":"A","explanation":{"en":"Penicillin is appropriate when beta-hemolytic streptococci are the sole confirmed pathogen because it does not reliably cover S. aureus.","ar":"يكون البنسلين مناسبًا عندما تكون العقديات الحالّة للدم بيتا هي الممرض الوحيد المؤكد لأنه لا يغطي العنقوديات الذهبية بصورة موثوقة."},"reasoning":{"en":"Focus on narrow therapy is justified only after excluding staphylococcal involvement. This clue supports option A and makes the alternatives less consistent with the chapter’s clinical pattern.","ar":"ركّز على لا يبرر العلاج الضيق إلا بعد استبعاد مشاركة العنقوديات. تدعم هذه العلامة الخيار A وتجعل البدائل أقل توافقًا مع النمط السريري المذكور في الفصل."},"image":null},{"id":"Q021","topic":"impetigo","topicEn":"Impetigo","topicAr":"القوباء","type":"Treatment","difficulty":"Medium","source":"PDF p. 10","question":{"en":"Why are fluoroquinolones not recommended routinely for impetigo?","ar":"لماذا لا تُوصى الفلوروكينولونات روتينيًا لعلاج القوباء؟"},"options":[{"letter":"A","en":"High MRSA resistance and risk of selecting resistance","ar":"ارتفاع مقاومة MRSA وخطر انتقاء المقاومة"},{"letter":"B","en":"They never penetrate skin","ar":"لا تنفذ إلى الجلد مطلقًا"},{"letter":"C","en":"They are only antifungal agents","ar":"هي مضادات فطرية فقط"},{"letter":"D","en":"They invariably cause renal failure","ar":"تسبب فشلًا كلويًا دائمًا"}],"correct":"A","explanation":{"en":"The chapter advises against fluoroquinolones because MRSA resistance is high and resistance can emerge during therapy.","ar":"ينصح الفصل بتجنب الفلوروكينولونات بسبب ارتفاع مقاومة MRSA وإمكانية ظهور المقاومة أثناء العلاج."},"reasoning":{"en":"Focus on the concern is antimicrobial stewardship and unreliable activity, not lack of all skin penetration. This clue supports option A and makes the alternatives less consistent with the chapter’s clinical pattern.","ar":"ركّز على المشكلة تتعلق بترشيد المضادات وعدم موثوقية الفعالية وليست انعدام النفاذ للجلد. تدعم هذه العلامة الخيار A وتجعل البدائل أقل توافقًا مع النمط السريري المذكور في الفصل."},"image":null},{"id":"Q022","topic":"impetigo","topicEn":"Impetigo","topicAr":"القوباء","type":"Image","difficulty":"Medium","source":"PDF p. 6","question":{"en":"The image shows annular lesions formed by central healing and peripheral extension. Which special variant is most likely?","ar":"تُظهر الصورة آفات حلقية ناتجة عن الالتئام المركزي والامتداد المحيطي. ما النوع الخاص الأكثر احتمالًا؟"},"options":[{"letter":"A","en":"Circinate impetigo","ar":"القوباء الحلقية"},{"letter":"B","en":"Crusted impetigo","ar":"القوباء المتقشرة"},{"letter":"C","en":"Ecthyma gangrenosum","ar":"الإكثيما الغنغرينية"},{"letter":"D","en":"Erythrasma","ar":"الإريثرازما"}],"correct":"A","explanation":{"en":"Circinate impetigo may develop when a bulla extends peripherally while healing centrally, or when vesicles form a circular arrangement.","ar":"قد تتكون القوباء الحلقية عندما تمتد الفقاعة محيطيًا مع الالتئام مركزيًا أو تنتظم الحويصلات في شكل دائري."},"reasoning":{"en":"Focus on the annular pattern with central clearing is the defining visual clue. This clue supports option A and makes the alternatives less consistent with the chapter’s clinical pattern.","ar":"ركّز على النمط الحلقي مع الصفاء المركزي هو العلامة البصرية المحددة. تدعم هذه العلامة الخيار A وتجعل البدائل أقل توافقًا مع النمط السريري المذكور في الفصل."},"image":"data:image/webp;base64,"},{"id":"Q023","topic":"impetigo","topicEn":"Impetigo","topicAr":"القوباء","type":"Case","difficulty":"Medium","source":"PDF p. 6","question":{"en":"A child with scalp pediculosis develops thick yellow crusts over superficial lesions. Which variant is most likely?","ar":"طفل يعاني قمل فروة الرأس وظهرت لديه قشور صفراء سميكة فوق آفات سطحية. ما النوع الأكثر احتمالًا؟"},"options":[{"letter":"A","en":"Crusted impetigo","ar":"القوباء المتقشرة"},{"letter":"B","en":"Bullous impetigo","ar":"القوباء الفقاعية"},{"letter":"C","en":"Carbuncle","ar":"الجمرة"},{"letter":"D","en":"Anthrax","ar":"الجمرة الخبيثة"}],"correct":"A","explanation":{"en":"Crusted impetigo is described as thick yellow crusting, often on the scalp as a complication of pediculosis.","ar":"تتميز القوباء المتقشرة بقشور صفراء سميكة، وغالبًا تظهر على فروة الرأس كمضاعفة للقمل."},"reasoning":{"en":"Focus on scalp location plus pediculosis and thick crusts identify this special variant. This clue supports option A and makes the alternatives less consistent with the chapter’s clinical pattern.","ar":"ركّز على يحدد موضع فروة الرأس مع القمل والقشور السميكة هذا النوع الخاص. تدعم هذه العلامة الخيار A وتجعل البدائل أقل توافقًا مع النمط السريري المذكور في الفصل."},"image":null},{"id":"Q024","topic":"impetigo","topicEn":"Impetigo","topicAr":"القوباء","type":"Case","difficulty":"Medium","source":"PDF pp. 4-5","question":{"en":"A child with atopic dermatitis develops multiple superficial honey-crusted erosions on previously inflamed skin. Which explanation is best?","ar":"طفل مصاب بالتهاب الجلد التأتبي ظهرت لديه تآكلات سطحية متعددة ذات قشور عسلية فوق جلد ملتهب سابقًا. ما التفسير الأفضل؟"},"options":[{"letter":"A","en":"Barrier disruption predisposed to secondary non-bullous impetigo","ar":"اختلال الحاجز مهّد لقوباء غير فقاعية ثانوية"},{"letter":"B","en":"The lesions prove deep necrotizing fasciitis","ar":"تثبت الآفات وجود التهاب لفافة نخري عميق"},{"letter":"C","en":"Atopic dermatitis prevents bacterial colonization","ar":"يمنع التهاب الجلد التأتبي الاستعمار البكتيري"},{"letter":"D","en":"This is necessarily a drug eruption","ar":"هذا طفح دوائي بالضرورة"}],"correct":"A","explanation":{"en":"Pre-existing dermatoses disrupt the epidermal barrier and allow secondary impetiginization, commonly with non-bullous morphology.","ar":"تُخل الأمراض الجلدية السابقة بالحاجز البشروي وتسمح بعدوى بكتيرية ثانوية غالبًا بشكل غير فقاعي."},"reasoning":{"en":"Focus on the combination of a damaged barrier and honey crusts supports secondary impetigo. This clue supports option A and makes the alternatives less consistent with the chapter’s clinical pattern.","ar":"ركّز على يدعم اجتماع تلف الحاجز والقشور العسلية القوباء الثانوية. تدعم هذه العلامة الخيار A وتجعل البدائل أقل توافقًا مع النمط السريري المذكور في الفصل."},"image":null},{"id":"Q025","topic":"impetigo","topicEn":"Impetigo","topicAr":"القوباء","type":"Image","difficulty":"Easy","source":"PDF p. 4","question":{"en":"What is the most likely diagnosis shown by the perioral honey-colored crusting in the image?","ar":"ما التشخيص الأكثر احتمالًا للصورة التي تُظهر قشورًا بلون العسل حول الفم؟"},"options":[{"letter":"A","en":"Non-bullous impetigo","ar":"القوباء غير الفقاعية"},{"letter":"B","en":"Erysipelas","ar":"الحمرة"},{"letter":"C","en":"Erythrasma","ar":"الإريثرازما"},{"letter":"D","en":"Furuncle","ar":"الدمل"}],"correct":"A","explanation":{"en":"Perioral honey-colored crusts over superficial erosions are classic for non-bullous impetigo.","ar":"القشور العسلية حول الفم فوق تآكلات سطحية علامة كلاسيكية للقوباء غير الفقاعية."},"reasoning":{"en":"Focus on morphology and facial distribution are highly characteristic. This clue supports option A and makes the alternatives less consistent with the chapter’s clinical pattern.","ar":"ركّز على الشكل وتوزع الوجه مميزان بدرجة كبيرة. تدعم هذه العلامة الخيار A وتجعل البدائل أقل توافقًا مع النمط السريري المذكور في الفصل."},"image":"data:image/webp;base64,"},{"id":"Q026","topic":"impetigo","topicEn":"Impetigo","topicAr":"القوباء","type":"Image","difficulty":"Medium","source":"PDF p. 5","question":{"en":"The image shows a superficial fragile erosion after rupture of a thin-roofed bulla. Which diagnosis best fits?","ar":"تُظهر الصورة تآكلًا سطحيًا هشًا بعد تمزق فقاعة رقيقة السقف. أي تشخيص يناسب أكثر؟"},"options":[{"letter":"A","en":"Bullous impetigo","ar":"القوباء الفقاعية"},{"letter":"B","en":"Ecthyma","ar":"الإكثيما"},{"letter":"C","en":"Carbuncle","ar":"الجمرة"},{"letter":"D","en":"Cellulitis","ar":"التهاب النسيج الخلوي"}],"correct":"A","explanation":{"en":"Bullous impetigo produces superficial thin-roofed bullae that rupture easily and leave moist erosions with a collarette.","ar":"تُنتج القوباء الفقاعية فقاعات سطحية رقيقة السقف تتمزق بسهولة وتترك تآكلات رطبة مع طوق قشري."},"reasoning":{"en":"Focus on a fragile superficial bulla distinguishes it from ulcerative or deep infections. This clue supports option A and makes the alternatives less consistent with the chapter’s clinical pattern.","ar":"ركّز على تميز الفقاعة السطحية الهشة الحالة عن العدوى التقرحية أو العميقة. تدعم هذه العلامة الخيار A وتجعل البدائل أقل توافقًا مع النمط السريري المذكور في الفصل."},"image":"data:image/webp;base64,"},{"id":"Q027","topic":"ecthyma","topicEn":"Ecthyma","topicAr":"الإكثيما","type":"MCQ","difficulty":"Easy","source":"PDF p. 7","question":{"en":"How does ecthyma differ anatomically from impetigo?","ar":"كيف تختلف الإكثيما تشريحيًا عن القوباء؟"},"options":[{"letter":"A","en":"It extends into the dermis","ar":"تمتد إلى الأدمة"},{"letter":"B","en":"It is confined to hair shafts only","ar":"تقتصر على ساق الشعرة فقط"},{"letter":"C","en":"It affects skeletal muscle first","ar":"تُصيب العضلات الهيكلية أولًا"},{"letter":"D","en":"It is limited to mucosa","ar":"تقتصر على الأغشية المخاطية"}],"correct":"A","explanation":{"en":"Ecthyma is a deeper form of impetigo in which infection penetrates through the epidermis into the dermis.","ar":"الإكثيما شكل أعمق من القوباء تخترق فيه العدوى البشرة لتصل إلى الأدمة."},"reasoning":{"en":"Focus on dermal extension explains ulceration and scarring. This clue supports option A and makes the alternatives less consistent with the chapter’s clinical pattern.","ar":"ركّز على يفسر الامتداد إلى الأدمة التقرح والتندب. تدعم هذه العلامة الخيار A وتجعل البدائل أقل توافقًا مع النمط السريري المذكور في الفصل."},"image":null},{"id":"Q028","topic":"ecthyma","topicEn":"Ecthyma","topicAr":"الإكثيما","type":"MCQ","difficulty":"Medium","source":"PDF p. 7","question":{"en":"Which lesion sequence is most typical of ecthyma?","ar":"أي تسلسل للآفة هو الأكثر نموذجية للإكثيما؟"},"options":[{"letter":"A","en":"Vesicle or pustule → thick dark crust → punched-out ulcer","ar":"حويصلة أو بثرة ← قشرة داكنة سميكة ← قرحة محفورة"},{"letter":"B","en":"Macule → wheal → transient clearing","ar":"لطخة ← شرية ← زوال عابر"},{"letter":"C","en":"Bullae → generalized desquamation without ulcer","ar":"فقاعات ← تقشر عام دون قرحة"},{"letter":"D","en":"Papule → painless black eschar with massive edema","ar":"حطاطة ← قشرة سوداء غير مؤلمة مع وذمة شديدة"}],"correct":"A","explanation":{"en":"Ecthyma starts as a vesicle or pustule and progresses to an adherent crust over a shallow punched-out ulcer.","ar":"تبدأ الإكثيما كحويصلة أو بثرة ثم تتطور إلى قشرة ملتصقة تغطي قرحة سطحية محفورة."},"reasoning":{"en":"Focus on the punched-out ulcer under an adherent crust is the key morphology. This clue supports option A and makes the alternatives less consistent with the chapter’s clinical pattern.","ar":"ركّز على القرحة المحفورة تحت قشرة ملتصقة هي الشكل المميز. تدعم هذه العلامة الخيار A وتجعل البدائل أقل توافقًا مع النمط السريري المذكور في الفصل."},"image":null},{"id":"Q029","topic":"ecthyma","topicEn":"Ecthyma","topicAr":"الإكثيما","type":"MCQ","difficulty":"Easy","source":"PDF p. 7","question":{"en":"Which sites are commonly affected by ecthyma?","ar":"ما المواضع التي تُصاب شائعًا بالإكثيما؟"},"options":[{"letter":"A","en":"Legs, buttocks, and thighs","ar":"الساقان والأليتان والفخذان"},{"letter":"B","en":"Only palms and soles","ar":"راحة اليدين وأخمص القدمين فقط"},{"letter":"C","en":"Only oral mucosa","ar":"الغشاء المخاطي الفموي فقط"},{"letter":"D","en":"Only the scalp","ar":"فروة الرأس فقط"}],"correct":"A","explanation":{"en":"Ecthyma commonly involves the legs, buttocks, and thighs.","ar":"تُصيب الإكثيما غالبًا الساقين والأليتين والفخذين."},"reasoning":{"en":"Focus on the lower-body distribution is typical in neglected or vulnerable patients. This clue supports option A and makes the alternatives less consistent with the chapter’s clinical pattern.","ar":"ركّز على يشيع التوزع في الجزء السفلي من الجسم لدى المرضى المهملين أو الضعفاء. تدعم هذه العلامة الخيار A وتجعل البدائل أقل توافقًا مع النمط السريري المذكور في الفصل."},"image":null},{"id":"Q030","topic":"ecthyma","topicEn":"Ecthyma","topicAr":"الإكثيما","type":"Case","difficulty":"Medium","source":"PDF p. 7","question":{"en":"A malnourished patient has a slowly healing ulcer under a thick bloody-brown crust. What outcome is most likely after healing?","ar":"مريض يعاني سوء التغذية لديه قرحة بطيئة الالتئام تحت قشرة بنية دموية سميكة. ما النتيجة الأكثر احتمالًا بعد الالتئام؟"},"options":[{"letter":"A","en":"Scarring or post-inflammatory hyperpigmentation","ar":"تندب أو فرط تصبغ تالٍ للالتهاب"},{"letter":"B","en":"Complete resolution within hours","ar":"زوال كامل خلال ساعات"},{"letter":"C","en":"Permanent depigmentation in every case","ar":"فقد تصبغ دائم في كل الحالات"},{"letter":"D","en":"No skin change because the dermis is spared","ar":"لا تغير جلدي لأن الأدمة غير مصابة"}],"correct":"A","explanation":{"en":"Because ecthyma reaches the dermis, healing may take weeks and can leave a scar or post-inflammatory hyperpigmentation.","ar":"لأن الإكثيما تصل إلى الأدمة فقد يستغرق الالتئام أسابيع ويترك ندبة أو فرط تصبغ تالٍ للالتهاب."},"reasoning":{"en":"Focus on dermal injury predicts residual skin change. This clue supports option A and makes the alternatives less consistent with the chapter’s clinical pattern.","ar":"ركّز على تتنبأ إصابة الأدمة ببقاء تغير جلدي. تدعم هذه العلامة الخيار A وتجعل البدائل أقل توافقًا مع النمط السريري المذكور في الفصل."},"image":null},{"id":"Q031","topic":"ecthyma","topicEn":"Ecthyma","topicAr":"الإكثيما","type":"Case","difficulty":"Medium","source":"PDF p. 7","question":{"en":"Which patient is at greatest risk of ecthyma rather than simple impetigo?","ar":"أي مريض أكثر عرضة للإكثيما بدلًا من القوباء البسيطة؟"},"options":[{"letter":"A","en":"An immunocompromised patient with poor hygiene and malnutrition","ar":"مريض مثبط المناعة مع سوء نظافة وسوء تغذية"},{"letter":"B","en":"A healthy adult with intact skin and no exposures","ar":"بالغ سليم ذو جلد سليم دون تعرضات"},{"letter":"C","en":"A patient with isolated allergic rhinitis","ar":"مريض لديه التهاب أنف تحسسي فقط"},{"letter":"D","en":"A patient after brief sun exposure","ar":"مريض بعد تعرض قصير للشمس"}],"correct":"A","explanation":{"en":"Neglect, poor hygiene, malnutrition, and immunocompromise favor deeper progression from impetigo to ecthyma.","ar":"يساعد الإهمال وسوء النظافة وسوء التغذية وتثبيط المناعة على تحول القوباء إلى عدوى أعمق هي الإكثيما."},"reasoning":{"en":"Focus on multiple host vulnerabilities increase depth and delayed healing. This clue supports option A and makes the alternatives less consistent with the chapter’s clinical pattern.","ar":"ركّز على تزيد عوامل ضعف المضيف المتعددة عمق العدوى وتأخر الالتئام. تدعم هذه العلامة الخيار A وتجعل البدائل أقل توافقًا مع النمط السريري المذكور في الفصل."},"image":null},{"id":"Q032","topic":"ecthyma","topicEn":"Ecthyma","topicAr":"الإكثيما","type":"Treatment","difficulty":"Medium","source":"PDF pp. 7-10","question":{"en":"What management is generally required for ecthyma?","ar":"ما التدبير المطلوب عادةً للإكثيما؟"},"options":[{"letter":"A","en":"Systemic antibiotics plus local wound care","ar":"مضادات حيوية جهازية مع عناية موضعية بالجرح"},{"letter":"B","en":"Moisturizer alone","ar":"مرطب فقط"},{"letter":"C","en":"Topical antifungal alone","ar":"مضاد فطري موضعي فقط"},{"letter":"D","en":"Observation without cleaning","ar":"المراقبة دون تنظيف"}],"correct":"A","explanation":{"en":"Ecthyma is deeper and ulcerative, so systemic antibacterial therapy and local wound care are needed.","ar":"الإكثيما أعمق وتقرحية، ولذلك تحتاج علاجًا بكتيريًا جهازيًا وعناية موضعية بالجرح."},"reasoning":{"en":"Focus on depth and ulceration make topical-only therapy insufficient. This clue supports option A and makes the alternatives less consistent with the chapter’s clinical pattern.","ar":"ركّز على يجعلان العمق والتقرح العلاج الموضعي وحده غير كافٍ. تدعم هذه العلامة الخيار A وتجعل البدائل أقل توافقًا مع النمط السريري المذكور في الفصل."},"image":null},{"id":"Q033","topic":"ecthyma","topicEn":"Ecthyma","topicAr":"الإكثيما","type":"Treatment","difficulty":"Medium","source":"PDF p. 9","question":{"en":"A patient has multiple ecthyma lesions without MRSA risk. Which oral agent is a reasonable first-line choice?","ar":"مريض لديه آفات إكثيما متعددة دون خطر MRSA. أي دواء فموي يُعد خيارًا أوليًا معقولًا؟"},"options":[{"letter":"A","en":"Cephalexin","ar":"سيفاليكسين"},{"letter":"B","en":"Acyclovir","ar":"أسيكلوفير"},{"letter":"C","en":"Terbinafine","ar":"تيربينافين"},{"letter":"D","en":"Metronidazole alone","ar":"ميترونيدازول وحده"}],"correct":"A","explanation":{"en":"Cephalexin provides systemic coverage for common streptococcal and methicillin-sensitive staphylococcal causes.","ar":"يوفر السيفاليكسين تغطية جهازية للأسباب العقدية والعنقودية الحساسة للميثيسيلين الشائعة."},"reasoning":{"en":"Focus on non-MRSA ecthyma should be covered for both streptococci and MSSA. This clue supports option A and makes the alternatives less consistent with the chapter’s clinical pattern.","ar":"ركّز على ينبغي تغطية العقديات وMSSA في الإكثيما دون خطر MRSA. تدعم هذه العلامة الخيار A وتجعل البدائل أقل توافقًا مع النمط السريري المذكور في الفصل."},"image":null},{"id":"Q034","topic":"ecthyma","topicEn":"Ecthyma","topicAr":"الإكثيما","type":"Image","difficulty":"Medium","source":"PDF p. 7","question":{"en":"The image shows a thick adherent crust over a punched-out ulcer. Which diagnosis is most likely?","ar":"تُظهر الصورة قشرة سميكة ملتصقة فوق قرحة محفورة. ما التشخيص الأكثر احتمالًا؟"},"options":[{"letter":"A","en":"Ecthyma","ar":"الإكثيما"},{"letter":"B","en":"Localized erythrasma","ar":"إريثرازما موضعية"},{"letter":"C","en":"Non-bullous impetigo only","ar":"قوباء غير فقاعية فقط"},{"letter":"D","en":"Hot-tub folliculitis","ar":"التهاب جريبات حمام ساخن"}],"correct":"A","explanation":{"en":"A punched-out ulcer beneath an adherent dark crust is characteristic of ecthyma.","ar":"تُعد القرحة المحفورة تحت قشرة داكنة ملتصقة مميزة للإكثيما."},"reasoning":{"en":"Focus on ulcer depth and adherent crust separate ecthyma from superficial impetigo. This clue supports option A and makes the alternatives less consistent with the chapter’s clinical pattern.","ar":"ركّز على يفرق عمق القرحة والقشرة الملتصقة الإكثيما عن القوباء السطحية. تدعم هذه العلامة الخيار A وتجعل البدائل أقل توافقًا مع النمط السريري المذكور في الفصل."},"image":"data:image/webp;base64,"},{"id":"Q035","topic":"erythrasma","topicEn":"Erythrasma","topicAr":"الإريثرازما","type":"MCQ","difficulty":"Easy","source":"PDF p. 11","question":{"en":"Which organism causes erythrasma?","ar":"ما الكائن المسبب للإريثرازما؟"},"options":[{"letter":"A","en":"Corynebacterium minutissimum","ar":"الوتدية الدقيقة"},{"letter":"B","en":"Streptococcus pyogenes","ar":"العقدية المقيحة"},{"letter":"C","en":"Bartonella henselae","ar":"بارتونيلا هينسيلا"},{"letter":"D","en":"Bacillus anthracis","ar":"العصوية الجمرية"}],"correct":"A","explanation":{"en":"Erythrasma is a superficial infection caused by the aerobic coryneform bacterium Corynebacterium minutissimum.","ar":"الإريثرازما عدوى سطحية تسببها بكتيريا وتدية هوائية تُسمى Corynebacterium minutissimum."},"reasoning":{"en":"Focus on the causative organism is a coryneform bacterium rather than a fungus. This clue supports option A and makes the alternatives less consistent with the chapter’s clinical pattern.","ar":"ركّز على المسبب بكتيريا وتدية وليس فطرًا. تدعم هذه العلامة الخيار A وتجعل البدائل أقل توافقًا مع النمط السريري المذكور في الفصل."},"image":null},{"id":"Q036","topic":"erythrasma","topicEn":"Erythrasma","topicAr":"الإريثرازما","type":"MCQ","difficulty":"Easy","source":"PDF p. 11","question":{"en":"Which distribution is most typical of erythrasma?","ar":"أي توزيع هو الأكثر شيوعًا للإريثرازما؟"},"options":[{"letter":"A","en":"Groin, axillae, toe webs, and other flexures","ar":"الأربية والإبط وبين أصابع القدم والثنيات الأخرى"},{"letter":"B","en":"Scalp only","ar":"فروة الرأس فقط"},{"letter":"C","en":"Extensor elbows only","ar":"باسطات المرفقين فقط"},{"letter":"D","en":"Oral mucosa only","ar":"الغشاء المخاطي الفموي فقط"}],"correct":"A","explanation":{"en":"Erythrasma favors intertriginous areas such as the groin, axillae, submammary folds, intergluteal cleft, and toe webs.","ar":"تفضل الإريثرازما مناطق الثنيات مثل الأربية والإبط وتحت الثدي وبين الأليتين وبين أصابع القدم."},"reasoning":{"en":"Focus on warm moist flexures support corynebacterial overgrowth. This clue supports option A and makes the alternatives less consistent with the chapter’s clinical pattern.","ar":"ركّز على تدعم الثنيات الدافئة الرطبة فرط نمو الوتديات. تدعم هذه العلامة الخيار A وتجعل البدائل أقل توافقًا مع النمط السريري المذكور في الفصل."},"image":null},{"id":"Q037","topic":"erythrasma","topicEn":"Erythrasma","topicAr":"الإريثرازما","type":"MCQ","difficulty":"Medium","source":"PDF p. 11","question":{"en":"What Wood lamp finding supports erythrasma?","ar":"ما نتيجة مصباح وود التي تدعم تشخيص الإريثرازما؟"},"options":[{"letter":"A","en":"Coral-red fluorescence","ar":"تألق أحمر مرجاني"},{"letter":"B","en":"Bright green fluorescence","ar":"تألق أخضر ساطع"},{"letter":"C","en":"No fluorescence in every case","ar":"غياب التألق في كل الحالات"},{"letter":"D","en":"Blue-white fluorescence from keratin","ar":"تألق أزرق أبيض من الكيراتين"}],"correct":"A","explanation":{"en":"Porphyrin production by C. minutissimum produces coral-red fluorescence under Wood light.","ar":"يؤدي إنتاج البورفيرين بواسطة C. minutissimum إلى تألق أحمر مرجاني تحت مصباح وود."},"reasoning":{"en":"Focus on the fluorescence color is a high-yield diagnostic discriminator. This clue supports option A and makes the alternatives less consistent with the chapter’s clinical pattern.","ar":"ركّز على لون التألق علامة تشخيصية فارقة عالية الأهمية. تدعم هذه العلامة الخيار A وتجعل البدائل أقل توافقًا مع النمط السريري المذكور في الفصل."},"image":null},{"id":"Q038","topic":"erythrasma","topicEn":"Erythrasma","topicAr":"الإريثرازما","type":"Case","difficulty":"Medium","source":"PDF p. 11","question":{"en":"An obese adult with diabetes has asymptomatic sharply demarcated reddish-brown groin patches with fine scale. Which diagnosis is most likely?","ar":"بالغ بدين مصاب بالسكري لديه لطخات بنية محمرة محددة بوضوح في الأربية مع قشور دقيقة ودون أعراض واضحة. ما التشخيص الأرجح؟"},"options":[{"letter":"A","en":"Erythrasma","ar":"الإريثرازما"},{"letter":"B","en":"Cellulitis","ar":"التهاب النسيج الخلوي"},{"letter":"C","en":"Carbuncle","ar":"الجمرة"},{"letter":"D","en":"Bullous impetigo","ar":"القوباء الفقاعية"}],"correct":"A","explanation":{"en":"Reddish-brown finely scaling patches in flexures, especially with obesity and diabetes, strongly suggest erythrasma.","ar":"تشير اللطخات البنية المحمرة ذات القشور الدقيقة في الثنيات، خصوصًا مع السمنة والسكري، بقوة إلى الإريثرازما."},"reasoning":{"en":"Focus on chronic flexural patches without marked inflammation differ from acute invasive infection. This clue supports option A and makes the alternatives less consistent with the chapter’s clinical pattern.","ar":"ركّز على تختلف اللطخات المزمنة في الثنيات دون التهاب واضح عن العدوى الغازية الحادة. تدعم هذه العلامة الخيار A وتجعل البدائل أقل توافقًا مع النمط السريري المذكور في الفصل."},"image":null},{"id":"Q039","topic":"erythrasma","topicEn":"Erythrasma","topicAr":"الإريثرازما","type":"Case","difficulty":"Medium","source":"PDF p. 11","question":{"en":"Which feature most helps distinguish erythrasma from candidal intertrigo?","ar":"أي علامة تساعد أكثر في التفريق بين الإريثرازما والتهاب الثنيات بالمبيضات؟"},"options":[{"letter":"A","en":"Coral-red fluorescence and absence of satellite pustules","ar":"التألق الأحمر المرجاني وغياب البثرات التابعة"},{"letter":"B","en":"Severe pain out of proportion","ar":"ألم شديد غير متناسب"},{"letter":"C","en":"Multiple draining sinuses","ar":"جيوب متعددة مفرغة"},{"letter":"D","en":"A central black eschar","ar":"قشرة سوداء مركزية"}],"correct":"A","explanation":{"en":"Erythrasma fluoresces coral-red and usually lacks the active inflammation and satellite lesions typical of candidiasis.","ar":"تتألق الإريثرازما بالأحمر المرجاني وتفتقر عادةً إلى الالتهاب النشط والآفات التابعة المميزة للمبيضات."},"reasoning":{"en":"Focus on Wood lamp appearance and lesion morphology separate bacterial erythrasma from candidiasis. This clue supports option A and makes the alternatives less consistent with the chapter’s clinical pattern.","ar":"ركّز على يفصل مظهر مصباح وود وشكل الآفة الإريثرازما البكتيرية عن المبيضات. تدعم هذه العلامة الخيار A وتجعل البدائل أقل توافقًا مع النمط السريري المذكور في الفصل."},"image":null},{"id":"Q040","topic":"erythrasma","topicEn":"Erythrasma","topicAr":"الإريثرازما","type":"Treatment","difficulty":"Easy","source":"PDF p. 12","question":{"en":"What is a first-line treatment for localized erythrasma?","ar":"ما علاج الخط الأول للإريثرازما الموضعية؟"},"options":[{"letter":"A","en":"Topical clindamycin or erythromycin","ar":"كليندامايسين أو إريثرومايسين موضعي"},{"letter":"B","en":"IV vancomycin","ar":"فانكوميسين وريدي"},{"letter":"C","en":"Oral amphotericin B","ar":"أمفوتيريسين B فموي"},{"letter":"D","en":"Urgent incision and drainage","ar":"شق وتصريف عاجل"}],"correct":"A","explanation":{"en":"Localized erythrasma is treated with topical clindamycin, erythromycin, or fusidic acid, commonly twice daily for 14 days.","ar":"تُعالج الإريثرازما الموضعية بالكليندامايسين أو الإريثرومايسين أو حمض الفيوسيديك موضعيًا، وغالبًا مرتين يوميًا لمدة 14 يومًا."},"reasoning":{"en":"Focus on a superficial localized infection usually responds to topical antibacterial therapy. This clue supports option A and makes the alternatives less consistent with the chapter’s clinical pattern.","ar":"ركّز على تستجيب العدوى السطحية الموضعية عادةً للعلاج البكتيري الموضعي. تدعم هذه العلامة الخيار A وتجعل البدائل أقل توافقًا مع النمط السريري المذكور في الفصل."},"image":null},{"id":"Q041","topic":"erythrasma","topicEn":"Erythrasma","topicAr":"الإريثرازما","type":"Treatment","difficulty":"Medium","source":"PDF p. 12","question":{"en":"Which approach is appropriate for extensive erythrasma?","ar":"ما التدبير المناسب للإريثرازما الواسعة؟"},"options":[{"letter":"A","en":"Oral clarithromycin or erythromycin","ar":"كلاريثروميسين أو إريثرومايسين فموي"},{"letter":"B","en":"Topical anesthetic alone","ar":"مخدر موضعي فقط"},{"letter":"C","en":"Immediate surgical excision","ar":"استئصال جراحي فوري"},{"letter":"D","en":"Antiviral therapy","ar":"علاج مضاد للفيروسات"}],"correct":"A","explanation":{"en":"Widespread involvement may require an oral macrolide such as clarithromycin or erythromycin.","ar":"قد تحتاج الإصابة الواسعة إلى ماكروليد فموي مثل الكلاريثروميسين أو الإريثرومايسين."},"reasoning":{"en":"Focus on extent is the reason to escalate from topical to systemic treatment. This clue supports option A and makes the alternatives less consistent with the chapter’s clinical pattern.","ar":"ركّز على اتساع الإصابة هو سبب الانتقال من العلاج الموضعي إلى الجهازي. تدعم هذه العلامة الخيار A وتجعل البدائل أقل توافقًا مع النمط السريري المذكور في الفصل."},"image":null},{"id":"Q042","topic":"erythrasma","topicEn":"Erythrasma","topicAr":"الإريثرازما","type":"Image","difficulty":"Medium","source":"PDF p. 11","question":{"en":"The image shows a reddish-brown flexural patch with coral-red fluorescence under Wood light. What is the diagnosis?","ar":"تُظهر الصورة لطخة بنية محمرة في أحد الثنيات مع تألق أحمر مرجاني تحت مصباح وود. ما التشخيص؟"},"options":[{"letter":"A","en":"Erythrasma","ar":"الإريثرازما"},{"letter":"B","en":"Tinea corporis","ar":"سعفة الجسم"},{"letter":"C","en":"Cellulitis","ar":"التهاب النسيج الخلوي"},{"letter":"D","en":"Ecthyma","ar":"الإكثيما"}],"correct":"A","explanation":{"en":"The combination of an intertriginous reddish-brown patch and coral-red fluorescence is characteristic of erythrasma.","ar":"يُعد اجتماع لطخة بنية محمرة في الثنيات مع التألق الأحمر المرجاني مميزًا للإريثرازما."},"reasoning":{"en":"Focus on the Wood lamp finding confirms the visual pattern. This clue supports option A and makes the alternatives less consistent with the chapter’s clinical pattern.","ar":"ركّز على تؤكد نتيجة مصباح وود النمط البصري. تدعم هذه العلامة الخيار A وتجعل البدائل أقل توافقًا مع النمط السريري المذكور في الفصل."},"image":"data:image/webp;base64,"},{"id":"Q043","topic":"erysipelas","topicEn":"Erysipelas","topicAr":"الحمرة","type":"MCQ","difficulty":"Easy","source":"PDF p. 13","question":{"en":"Which tissues are primarily involved in erysipelas?","ar":"ما الأنسجة التي تُصاب أساسًا في الحمرة؟"},"options":[{"letter":"A","en":"Superficial dermis and lymphatic vessels","ar":"الأدمة السطحية والأوعية اللمفية"},{"letter":"B","en":"Deep skeletal muscle only","ar":"العضلات الهيكلية العميقة فقط"},{"letter":"C","en":"Bone marrow","ar":"نخاع العظم"},{"letter":"D","en":"Hair shaft without skin involvement","ar":"ساق الشعرة دون الجلد"}],"correct":"A","explanation":{"en":"Erysipelas is an acute infection of the superficial dermis and upper lymphatic channels.","ar":"الحمرة عدوى حادة تصيب الأدمة السطحية والقنوات اللمفية العلوية."},"reasoning":{"en":"Focus on superficial lymphatic spread produces the raised sharply defined edge. This clue supports option A and makes the alternatives less consistent with the chapter’s clinical pattern.","ar":"ركّز على يُنتج الانتشار اللمفي السطحي الحافة المرتفعة المحددة بوضوح. تدعم هذه العلامة الخيار A وتجعل البدائل أقل توافقًا مع النمط السريري المذكور في الفصل."},"image":null},{"id":"Q044","topic":"erysipelas","topicEn":"Erysipelas","topicAr":"الحمرة","type":"MCQ","difficulty":"Easy","source":"PDF pp. 13, 15","question":{"en":"What is the most common cause of erysipelas?","ar":"ما السبب الأكثر شيوعًا للحمرة؟"},"options":[{"letter":"A","en":"Group A beta-hemolytic Streptococcus pyogenes","ar":"العقدية المقيحة من المجموعة A الحالّة للدم بيتا"},{"letter":"B","en":"Bartonella henselae","ar":"بارتونيلا هينسيلا"},{"letter":"C","en":"Corynebacterium minutissimum","ar":"الوتدية الدقيقة"},{"letter":"D","en":"Bacillus anthracis","ar":"العصوية الجمرية"}],"correct":"A","explanation":{"en":"Group A beta-hemolytic streptococci, especially S. pyogenes, are the leading cause.","ar":"العقديات الحالّة للدم بيتا من المجموعة A، خصوصًا S. pyogenes، هي السبب الرئيسي."},"reasoning":{"en":"Focus on the classic organism matches the nonpurulent superficial lymphatic pattern. This clue supports option A and makes the alternatives less consistent with the chapter’s clinical pattern.","ar":"ركّز على يتوافق الميكروب الكلاسيكي مع النمط السطحي اللمفي غير القيحي. تدعم هذه العلامة الخيار A وتجعل البدائل أقل توافقًا مع النمط السريري المذكور في الفصل."},"image":null},{"id":"Q045","topic":"erysipelas","topicEn":"Erysipelas","topicAr":"الحمرة","type":"MCQ","difficulty":"Easy","source":"PDF p. 13","question":{"en":"Which border is most typical of erysipelas?","ar":"أي نوع من الحدود هو الأكثر شيوعًا في الحمرة؟"},"options":[{"letter":"A","en":"Raised and sharply demarcated","ar":"مرتفعة ومحددة بوضوح"},{"letter":"B","en":"Diffuse and poorly defined","ar":"منتشرة وغير محددة"},{"letter":"C","en":"Completely normal surrounding skin","ar":"جلد محيط طبيعي تمامًا"},{"letter":"D","en":"A punched-out ulcer edge","ar":"حافة قرحة محفورة"}],"correct":"A","explanation":{"en":"Erysipelas produces a bright, shiny, raised plaque with a well-demarcated border.","ar":"تُحدث الحمرة لويحة ساطعة لامعة مرتفعة ذات حدود محددة بوضوح."},"reasoning":{"en":"Focus on sharp elevation reflects superficial dermal and lymphatic involvement. This clue supports option A and makes the alternatives less consistent with the chapter’s clinical pattern.","ar":"ركّز على تعكس الحافة الحادة المرتفعة إصابة الأدمة السطحية واللمف. تدعم هذه العلامة الخيار A وتجعل البدائل أقل توافقًا مع النمط السريري المذكور في الفصل."},"image":null},{"id":"Q046","topic":"erysipelas","topicEn":"Erysipelas","topicAr":"الحمرة","type":"Case","difficulty":"Medium","source":"PDF p. 13","question":{"en":"A patient has abrupt high fever followed by a shiny bright-red raised facial plaque with a sharp edge. What is the diagnosis?","ar":"مريض أصيب بحمى شديدة مفاجئة ثم ظهرت لويحة حمراء لامعة مرتفعة على الوجه ذات حافة حادة. ما التشخيص؟"},"options":[{"letter":"A","en":"Erysipelas","ar":"الحمرة"},{"letter":"B","en":"Cellulitis","ar":"التهاب النسيج الخلوي"},{"letter":"C","en":"Erythrasma","ar":"الإريثرازما"},{"letter":"D","en":"Folliculitis","ar":"التهاب الجريبات"}],"correct":"A","explanation":{"en":"Abrupt systemic symptoms plus a raised, sharply demarcated facial plaque are classic for erysipelas.","ar":"الأعراض الجهازية المفاجئة مع لويحة وجه مرتفعة محددة بوضوح علامات كلاسيكية للحمرة."},"reasoning":{"en":"Focus on onset, surface, and border collectively favor erysipelas. This clue supports option A and makes the alternatives less consistent with the chapter’s clinical pattern.","ar":"ركّز على يرجح نمط البداية والسطح والحدود الحمرة. تدعم هذه العلامة الخيار A وتجعل البدائل أقل توافقًا مع النمط السريري المذكور في الفصل."},"image":null},{"id":"Q047","topic":"erysipelas","topicEn":"Erysipelas","topicAr":"الحمرة","type":"MCQ","difficulty":"Medium","source":"PDF p. 13","question":{"en":"Which sites are most frequently affected by erysipelas?","ar":"ما المواضع الأكثر تعرضًا للحمرة؟"},"options":[{"letter":"A","en":"Face and lower limbs","ar":"الوجه والأطراف السفلية"},{"letter":"B","en":"Only the palms","ar":"راحة اليدين فقط"},{"letter":"C","en":"Only the oral cavity","ar":"التجويف الفموي فقط"},{"letter":"D","en":"Only the scalp","ar":"فروة الرأس فقط"}],"correct":"A","explanation":{"en":"The face and lower extremities are the most common sites.","ar":"يُعد الوجه والأطراف السفلية أكثر المواضع شيوعًا."},"reasoning":{"en":"Focus on site distribution supports diagnosis when paired with classic borders. This clue supports option A and makes the alternatives less consistent with the chapter’s clinical pattern.","ar":"ركّز على يدعم توزع الموضع التشخيص عند اجتماعه مع الحدود الكلاسيكية. تدعم هذه العلامة الخيار A وتجعل البدائل أقل توافقًا مع النمط السريري المذكور في الفصل."},"image":null},{"id":"Q048","topic":"erysipelas","topicEn":"Erysipelas","topicAr":"الحمرة","type":"Image","difficulty":"Medium","source":"PDF p. 13","question":{"en":"The facial lesion in the image is shiny, bright red, raised, and sharply demarcated. What is the most likely diagnosis?","ar":"الآفة الوجهية في الصورة لامعة وحمراء زاهية ومرتفعة ومحددة بوضوح. ما التشخيص الأرجح؟"},"options":[{"letter":"A","en":"Erysipelas","ar":"الحمرة"},{"letter":"B","en":"Ecthyma","ar":"الإكثيما"},{"letter":"C","en":"Carbuncle","ar":"الجمرة"},{"letter":"D","en":"Erythrasma","ar":"الإريثرازما"}],"correct":"A","explanation":{"en":"The sharply raised facial erythema is typical of erysipelas.","ar":"يُعد الاحمرار الوجهي المرتفع المحدد بوضوح نموذجياً للحمرة."},"reasoning":{"en":"Focus on the superficial sharply bordered plaque is the decisive visual clue. This clue supports option A and makes the alternatives less consistent with the chapter’s clinical pattern.","ar":"ركّز على اللويحة السطحية ذات الحدود الحادة هي العلامة البصرية الحاسمة. تدعم هذه العلامة الخيار A وتجعل البدائل أقل توافقًا مع النمط السريري المذكور في الفصل."},"image":"data:image/webp;base64,"},{"id":"Q049","topic":"erysipelas","topicEn":"Erysipelas","topicAr":"الحمرة","type":"Case","difficulty":"Medium","source":"PDF pp. 13-15","question":{"en":"Which finding most strongly favors erysipelas over cellulitis?","ar":"أي علامة ترجح الحمرة على التهاب النسيج الخلوي؟"},"options":[{"letter":"A","en":"A raised sharply defined border","ar":"حافة مرتفعة محددة بوضوح"},{"letter":"B","en":"Diffuse ill-defined erythema","ar":"احمرار منتشر غير محدد"},{"letter":"C","en":"Gradual progression without abrupt fever","ar":"تطور تدريجي دون حمى مفاجئة"},{"letter":"D","en":"Deep subcutaneous tenderness only","ar":"إيلام عميق تحت الجلد فقط"}],"correct":"A","explanation":{"en":"Erysipelas is more superficial and sharply demarcated, whereas cellulitis is deeper and has poorly defined margins.","ar":"الحمرة أكثر سطحية وحدودها أوضح، بينما التهاب النسيج الخلوي أعمق وحدوده غير واضحة."},"reasoning":{"en":"Focus on border quality is the highest-yield bedside discriminator. This clue supports option A and makes the alternatives less consistent with the chapter’s clinical pattern.","ar":"ركّز على نوع الحدود هو أهم علامة سريرية للتفريق. تدعم هذه العلامة الخيار A وتجعل البدائل أقل توافقًا مع النمط السريري المذكور في الفصل."},"image":null},{"id":"Q050","topic":"erysipelas","topicEn":"Erysipelas","topicAr":"الحمرة","type":"Treatment","difficulty":"Medium","source":"PDF pp. 19-20","question":{"en":"A stable outpatient has uncomplicated nonpurulent erysipelas. Which oral therapy is reasonable?","ar":"مريض مستقر بالعيادة لديه حمرة بسيطة غير قيحية. أي علاج فموي معقول؟"},"options":[{"letter":"A","en":"Amoxicillin or cephalexin","ar":"أموكسيسيلين أو سيفاليكسين"},{"letter":"B","en":"Ciprofloxacin for Pseudomonas","ar":"سيبروفلوكساسين للزائفة"},{"letter":"C","en":"Doxycycline alone for reliable streptococcal coverage","ar":"دوكسيسيكلين وحده لتغطية عقدية موثوقة"},{"letter":"D","en":"Fluconazole","ar":"فلوكونازول"}],"correct":"A","explanation":{"en":"Nonpurulent erysipelas is usually streptococcal, so an oral beta-lactam such as amoxicillin or cephalexin is appropriate when the patient is stable.","ar":"غالبًا تكون الحمرة غير القيحية عقدية، ولذلك يناسبها بيتا لاكتام فموي مثل الأموكسيسيلين أو السيفاليكسين عند استقرار المريض."},"reasoning":{"en":"Focus on therapy should prioritize streptococcal coverage rather than unnecessary MRSA or gram-negative coverage. This clue supports option A and makes the alternatives less consistent with the chapter’s clinical pattern.","ar":"ركّز على ينبغي أن يعطي العلاج الأولوية لتغطية العقديات بدل التغطية غير الضرورية لـMRSA أو سالبات الغرام. تدعم هذه العلامة الخيار A وتجعل البدائل أقل توافقًا مع النمط السريري المذكور في الفصل."},"image":null}]);
